INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cf446b4c-moex-00394', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '若行為後，刑法沒收之規定有修正，有關沒收之適用，下列敘述何者正確？', '["從行為時法", "從裁判時法", "從行為時法，但修法後之規定有利於行為人，則從裁判時法", "從裁判時法，但修法後之規定更不利於行為人，則從行為時法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00395', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '廚師甲為了獲取廚師乙所研發的某種食材秘方，將乙強行關在某間屋內。甲告知乙，倘若不說出來，就不 讓他離去。乙不得已，只好如實說出。依實務見解，甲之行為應如何論罪？', '["強制罪與剝奪行動自由罪，數罪併罰", "強制罪與剝奪行動自由罪，想像競合", "強制罪吸收剝奪行動自由罪", "剝奪行動自由罪吸收強制罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00396', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲、乙均為黑道大哥，相約談判。談判間，甲見乙觸摸口袋，以為乙要拔槍射殺甲，而出於防衛意思下手 殺乙，致乙死亡。甲主觀認知與客觀事實不一致。此種不一致，學理上稱為何種「錯誤」？', '["構成要件錯誤", "禁止錯誤", "容許構成要件錯誤", "打擊錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00397', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲持槍向乙宅開槍射擊，欲射殺乙，因乙事先走避未遭殺害。有關甲之刑責，依實務見解，下列敘述何者 正確？', '["甲成立殺人既遂罪", "甲成立殺人罪之障礙未遂", "甲成立殺人罪之中止未遂", "甲屬殺人罪之不能未遂而不罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00398', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關中止犯之敘述，下列何者錯誤？', '["中止犯之法律效果為減輕或免除其刑", "須實行中止行為", "中止行為須出於己意", "過失犯亦得適用中止犯之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00399', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲先殺A，A反抗甚鉅，甲之友人乙碰巧經過現場，立即加入甲之殺人行動，雙方基於共同殺A意思，由 乙抓住A而讓甲順利殺害A。甲、乙刑責為何？', '["甲、乙成立殺人既遂罪之共謀共同正犯", "甲、乙成立殺人既遂罪之相續共同正犯", "甲成立殺人既遂罪，乙成立殺人未遂罪", "甲成立殺人既遂罪之正犯，乙成立殺人既遂罪之幫助犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00400', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者非屬刑法上之共犯？', '["教唆犯", "心理幫助犯", "間接正犯", "物理幫助犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00401', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '緩刑期滿，緩刑之宣告未經撤銷者，原有之刑之宣告效力為何？', '["其刑之宣告以已執行論", "其刑之宣告失其效力", "其刑之宣告以受撤銷論", "其刑之宣告以赦免論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00402', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲對A使用之住宅縱火，事後反悔，打匿名電話通知消防隊，但該住宅已燒燬。有關甲之刑責，下列何者 正確？', '["甲成立放火既遂罪", "甲成立放火未遂罪之中止犯", "甲成立自首，得減輕其刑", "甲成立失火罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00403', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關自首的敘述，下列何者錯誤？', '["行為人主動向追訴機關申告自己尚未被發覺之犯罪而自願接受裁判", "自白與自首不同", "除有特別規定外，自首應減輕其刑", "不論以口頭或書面形式，皆可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
